    public function testGroupsAndLabelsDailyPowerValuesInUtc()
    {
        $start = self::$start;
        $end = self::$start + (1440 * 1800);

        $data = Power::fetch(self::$fileName)
            ->average()
            ->resolution('30m')
            ->start($start)
            ->end($end)
            ->run()
            ->group(DayInterval::for(1))
            ->labels(DayInterval::for(1))
            ->get();

        $this->assertSame(
            [
                '2023-11-15 00:00:00',
                '2023-11-16 00:00:00',
                '2023-11-17 00:00:00',
                '2023-11-18 00:00:00',
                '2023-11-19 00:00:00',
                '2023-11-20 00:00:00',
