                '2023-12-03 00:00:00',
                '2023-12-04 00:00:00',
                '2023-12-05 00:00:00',
                '2023-12-06 00:00:00',
                '2023-12-07 00:00:00',
                '2023-12-08 00:00:00',
                '2023-12-09 00:00:00',
                '2023-12-10 00:00:00',
                '2023-12-11 00:00:00',
                '2023-12-12 00:00:00',
                '2023-12-13 00:00:00',
                '2023-12-14 00:00:00',
            ],
            $data['timestamps'],
        );

        $this->assertEqualsWithDelta(
            [
